import{_ as e,o,c as r,a5 as d}from"./chunks/framework.C1VOsJ6A.js";const u=JSON.parse('{"title":"Account operator","description":"","frontmatter":{},"headers":[],"relativePath":"reference/components/account-operator.md","filePath":"reference/components/account-operator.md"}'),c={name:"reference/components/account-operator.md"};function a(n,t,s,i,l,h){return o(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="account-operator" tabindex="-1">Account operator <a class="header-anchor" href="#account-operator" aria-label="Permalink to &quot;Account operator&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>The account operator is the Platform Mesh component that converts defined account or organization entities into live control-plane structure. It owns reconciliation of the <code>Account</code>-Resource and ties its lifecycle to <strong>kcp</strong> workspace lifecycle. It ensures that each account gets the right isolation, workspace typing, and discoverable metadata.</p><p>Its role is to sit between the tenancy declared and how kcp exposes that tenancy without concerning itself with the implementation of identity or access management.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><h3 id="account-core-platform-mesh-io-v1alpha1" tabindex="-1"><strong>Account (<code>core.platform-mesh.io/v1alpha1</code>)</strong> <a class="header-anchor" href="#account-core-platform-mesh-io-v1alpha1" aria-label="Permalink to &quot;**Account (`core.platform-mesh.io/v1alpha1`)**&quot;">​</a></h3><p><code>Account</code> represents an entity in the workspace tree that can potentially hold other Accounts. <code>spec.type</code> currently only distinguishes an <strong>organization</strong> (type: <code>org</code>) from an <strong>account</strong> (type: <code>account</code>) but will possibly support other account types in the future. The spec carries display metadata, optional extensions, and structured <code>data</code>.</p><p>Reconciliation of an <code>Account</code> resource runs through the following steps:</p><ol><li>Webhooks validate the <code>Account</code> and set <code>spec.creator</code> to the respective Kubernetes user creating the resource.</li><li>Depending on the account type, one or more finalizers are added for later cleanup.</li><li>For accounts of type <code>org</code>, <code>WorkspaceTypes</code> for the organization&#39;s <code>Workspace</code> itself and its child <code>Accounts</code> are created.</li><li>A <code>Workspace</code> for the <code>Account</code> is created, using one of the above mentioned <code>WorkspaceTypes</code>, depending on the account type.</li><li>An <code>AccountInfo</code> resource of name <code>account</code> is created within the <code>Account</code>&#39;s <code>Workspace</code> and populated with information.</li><li>Readiness of the resource itself is blocked until the earlier created <code>Workspace</code> is ready, i.e. potential initializers have finished. This ensures that the <a href="/pr-preview/pr-125/reference/components/security-operator.html">security operator</a> is finished with its work.</li></ol><h3 id="accountinfo-core-platform-mesh-io-v1alpha1" tabindex="-1"><strong>AccountInfo (<code>core.platform-mesh.io/v1alpha1</code>)</strong> <a class="header-anchor" href="#accountinfo-core-platform-mesh-io-v1alpha1" aria-label="Permalink to &quot;**AccountInfo (`core.platform-mesh.io/v1alpha1`)**&quot;">​</a></h3><p>An <code>AccountInfo</code> resource with name <code>account</code> is created by the account operator in an account&#39;s workspace and holds information about the account the workspace belongs to. Its purpose is to expose that information to internal components that don&#39;t have information about or permission to workspaces/accounts higher up in the tree. It is comparable to the <code>LogicalCluster</code> object named <code>cluster</code> in every kcp workspace.</p><p>Reconciliation of an <code>AccountInfo</code> resource runs through the following steps:</p><ol><li>A finalizer is added. There are no other actions happening until the resource is deleted. Other components like the <a href="/pr-preview/pr-125/reference/components/security-operator.html">security operator</a> are expected to add their own finalizers when depending on information of the resource for e.g. <code>Workspace</code> termination.</li><li>During deletion, removal of the resource is blocked by withholding finalizer removal until the <code>Workspace</code>/<code>Account</code> does not have any child accounts anymore.</li></ol><p>Together, these pieces implement the account model described in <a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a> and the resource-oriented view in <a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a>.</p><h2 id="installation-configuration-notes" tabindex="-1">Installation / configuration notes <a class="header-anchor" href="#installation-configuration-notes" aria-label="Permalink to &quot;Installation / configuration notes&quot;">​</a></h2><h3 id="helm" tabindex="-1">Helm <a class="header-anchor" href="#helm" aria-label="Permalink to &quot;Helm&quot;">​</a></h3><p>The deployment chart is <strong><code>account-operator</code></strong> in <a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a>, CRDs ship as <strong><code>account-operator-crds</code></strong>. The authoritative values table is located in <a href="https://github.com/platform-mesh/helm-charts/blob/main/charts/account-operator/README.md" target="_blank" rel="noreferrer">charts/account-operator README</a>.</p><h3 id="cli-flags" tabindex="-1">CLI Flags <a class="header-anchor" href="#cli-flags" aria-label="Permalink to &quot;CLI Flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Type</th><th>Flag</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Account operator-specific</td><td><strong><code>--webhooks-enabled</code></strong></td><td><code>false</code></td><td>Enable the webhook server</td></tr><tr><td>Account operator-specific</td><td><strong><code>--webhooks-cert-dir</code></strong></td><td><code>certs</code></td><td>Webhook TLS certificate directory</td></tr><tr><td>Account operator-specific</td><td><strong><code>--webhooks-port</code></strong></td><td><code>9443</code></td><td>Webhook server listen port</td></tr><tr><td>Account operator-specific</td><td><strong><code>--webhooks-deny-list</code></strong></td><td><em>(empty)</em></td><td>Comma-separated denied organization names</td></tr><tr><td>Account operator-specific</td><td><strong><code>--webhooks-additional-account-types</code></strong></td><td><em>(empty)</em></td><td>Extra allowed <code>spec.type</code> values (<code>StringSlice</code>; repeat <strong><code>--flag=v</code></strong> per value)</td></tr><tr><td>Account operator-specific</td><td><strong><code>--subroutines-workspace-type-enabled</code></strong></td><td><code>true</code></td><td>WorkspaceType subroutine</td></tr><tr><td>Account operator-specific</td><td><strong><code>--subroutines-workspace-enabled</code></strong></td><td><code>true</code></td><td>Workspace subroutine</td></tr><tr><td>Account operator-specific</td><td><strong><code>--subroutines-workspace-ready-enabled</code></strong></td><td><code>true</code></td><td>Workspace ready subroutine</td></tr><tr><td>Account operator-specific</td><td><strong><code>--subroutines-account-info-enabled</code></strong></td><td><code>true</code></td><td>ManageAccountInfo subroutine</td></tr><tr><td>Account operator-specific</td><td><strong><code>--controllers-account-info-enabled</code></strong></td><td><code>true</code></td><td>AccountInfo controller (finalizer / deletion gate)</td></tr><tr><td>Account operator-specific</td><td><strong><code>--kcp-api-export-endpoint-slice-name</code></strong></td><td><code>core.platform-mesh.io</code></td><td>APIExportEndpointSlice name</td></tr><tr><td>Account operator-specific</td><td><strong><code>--kcp-provider-workspace</code></strong></td><td><code>root</code></td><td>Provider workspace</td></tr><tr><td>Common</td><td><strong><code>--debug-label-value</code></strong></td><td><em>(empty)</em></td><td>Debug label value for controller filters</td></tr><tr><td>Common</td><td><strong><code>--max-concurrent-reconciles</code></strong></td><td><code>10</code></td><td>Max concurrent reconciles per controller</td></tr><tr><td>Common</td><td><strong><code>--environment</code></strong></td><td><em>(empty)</em></td><td>Service environment label</td></tr><tr><td>Common</td><td><strong><code>--region</code></strong></td><td><code>local</code></td><td>Region label (e.g. local, staging, prod)</td></tr><tr><td>Common</td><td><strong><code>--kubeconfig</code></strong></td><td><em>(empty)</em></td><td>Kubeconfig file path</td></tr><tr><td>Common</td><td><strong><code>--is-local</code></strong></td><td><code>false</code></td><td>Mark execution as local</td></tr><tr><td>Common</td><td><strong><code>--image-name</code></strong></td><td><em>(empty)</em></td><td>Image name metadata</td></tr><tr><td>Common</td><td><strong><code>--image-tag</code></strong></td><td><em>(empty)</em></td><td>Image tag metadata</td></tr><tr><td>Common</td><td><strong><code>--log-level</code></strong></td><td><code>info</code></td><td>Log level</td></tr><tr><td>Common</td><td><strong><code>--no-json</code></strong></td><td><code>false</code></td><td>Disable JSON logs</td></tr><tr><td>Common</td><td><strong><code>--shutdown-timeout</code></strong></td><td><code>1m</code></td><td>Graceful shutdown timeout</td></tr><tr><td>Common</td><td><strong><code>--metrics-bind-address</code></strong></td><td><code>:9090</code></td><td>Metrics bind address</td></tr><tr><td>Common</td><td><strong><code>--metrics-secure</code></strong></td><td><code>false</code></td><td>Serve metrics over HTTPS</td></tr><tr><td>Common</td><td><strong><code>--tracing-enabled</code></strong></td><td><code>false</code></td><td>Enable OTLP tracing</td></tr><tr><td>Common</td><td><strong><code>--tracing-config-service-name</code></strong></td><td><em>(empty)</em></td><td>Trace resource service name</td></tr><tr><td>Common</td><td><strong><code>--tracing-config-service-version</code></strong></td><td><em>(empty)</em></td><td>Trace resource service version</td></tr><tr><td>Common</td><td><strong><code>--tracing-config-collector-endpoint</code></strong></td><td><em>(empty)</em></td><td>OTLP collector endpoint</td></tr><tr><td>Common</td><td><strong><code>--enable-http2</code></strong></td><td><code>true</code></td><td>HTTP/2 for metrics and webhook servers</td></tr><tr><td>Common</td><td><strong><code>--health-probe-bind-address</code></strong></td><td><code>:8090</code></td><td>Liveness/readiness bind address</td></tr><tr><td>Common</td><td><strong><code>--leader-elect</code></strong></td><td><code>false</code></td><td>Enable controller-manager leader election</td></tr></tbody></table><h3 id="environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment variables&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><strong><code>KUBECONFIG</code></strong></td><td>Kubeconfig to use</td></tr></tbody></table><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kind</th><th>Link</th></tr></thead><tbody><tr><td>Source repository</td><td><a href="https://github.com/platform-mesh/account-operator" target="_blank" rel="noreferrer">platform-mesh/account-operator</a></td></tr><tr><td>Helm charts</td><td><a href="https://github.com/platform-mesh/helm-charts" target="_blank" rel="noreferrer">platform-mesh/helm-charts</a> — <code>charts/account-operator</code>, <code>charts/account-operator-crds</code></td></tr></tbody></table><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/pr-preview/pr-125/concepts/account-model.html">Account model</a></li><li><a href="/pr-preview/pr-125/reference/resources/account-resource.html">Account resource</a></li><li><a href="./kcp.html">kcp</a></li></ul>',25)])])}const m=e(c,[["render",a]]);export{u as __pageData,m as default};
